final:
module RefModule (
    input clk,
    input rst,
    output reg [1:0] q
);
      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
        if (rst)
            q <= 2'b00;
        else begin
            case (q)
                2'b00: q <= 2'b01;
                2'b01: q <= 2'b11;
                2'b11: q <= 2'b10;
                2'b10: q <= 2'b00;
                default: q <= 2'b00;
            endcase
        end
    end
endmodule
